    return (
        <div className='modal'>
            <ul className='modal_1'>
                <li>
                    <a href='#'>잘자요</a>
                </li>
                <li>
                    <a href='#'>애칭 설정</a>
                </li>
                <li>
                    <a href='#'>Diray List</a>
                </li>
            </ul>
            <ul className='modal_2'>
                <li></li>
            </ul>
        </div>
    )
}


export default modal;
